214	/// Display a prompt, read a line from stdin, and log both together.
215	/// Returns the trimmed response.
216	pub fn prompt(msg: &str) -> Result<String, Box<dyn std::error::Error>> {
217	    use std::io::Write;
218	    eprint!("{msg}");
219	    std::io::stderr().flush()?;
220	    let mut response = String::new();
221	    std::io::stdin().read_line(&mut response)?;
222	    let trimmed = response.trim().to_string();
223	    info!("{msg}{trimmed}");
224	    Ok(trimmed)
225	}
