288	/// Format: changeID ochid(padded) [bookmarks |] first-line.
289	///
290	/// ochid column is left-padded to `width` characters. If no ochid, a blank
291	/// placeholder of that width is used. When `bookmarks` is non-empty it is
292	/// inserted before the title with a `|` separator (mirroring jj's
293	/// `Parent commit (@-): <chid> <hash> <bookmark> | <title>` style).
294	pub fn format_commit_with_ochid(commit: &Commit, width: usize, bookmarks: &str) -> String {
295	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
296	    let change_short = &change_hex[..change_hex.len().min(12)];
297	    let ochid = extract_ochid(commit).unwrap_or_default(); // OK: no ochid trailer → empty string
298	    let first_line = commit.description().lines().next().unwrap_or(""); // OK: obvious
299	    let title = if first_line.is_empty() {
300	        "(no description set)"
301	    } else {
302	        first_line
303	    };
304	    if bookmarks.is_empty() {
305	        format!("{change_short}  {ochid:<width$}  {title}")
306	    } else {
307	        format!("{change_short}  {ochid:<width$}  {bookmarks} | {title}")
308	    }
309	}
