531	/// Parse and evaluate a revset string, returning commit IDs.
532	pub fn resolve_revset(
533	    workspace: &Workspace,
534	    repo: &Arc<ReadonlyRepo>,
535	    revset_str: &str,
536	) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
537	    let aliases_map = RevsetAliasesMap::new();
538	    let fileset_aliases_map = FilesetAliasesMap::new();
539	    let extensions = RevsetExtensions::default();
540	    let workspace_root = workspace.workspace_root().to_path_buf();
541	    let path_converter = RepoPathUiConverter::Fs {
542	        cwd: workspace_root.clone(),
543	        base: workspace_root,
544	    };
545	    let workspace_name = workspace.workspace_name();
546	    let workspace_ctx = RevsetWorkspaceContext {
547	        path_converter: &path_converter,
548	        workspace_name,
549	    };
550	    let context = RevsetParseContext {
551	        aliases_map: &aliases_map,
552	        local_variables: HashMap::new(),
553	        user_email: "",
554	        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
555	        default_ignored_remote: None,
556	        fileset_aliases_map: &fileset_aliases_map,
557	        use_glob_by_default: false,
558	        extensions: &extensions,
559	        workspace: Some(workspace_ctx),
560	    };
561	
562	    let mut diagnostics = RevsetDiagnostics::new();
563	    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
564	
565	    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
566	    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
567	    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
568	    let revset = resolved.evaluate(repo.as_ref())?;
569	
570	    let mut commit_ids = Vec::new();
571	    for result in revset.iter() {
572	        commit_ids.push(result?);
573	    }
574	    Ok(commit_ids)
575	}
