577	/// Scan `jj bookmark list -a <name>` output for non-tracking remote refs.
578	///
579	/// Tracked remotes appear indented (`  @origin: ...`); non-tracking remotes
580	/// appear at column 0 as `<bookmark>@<remote>: ...`. Returns the
581	/// non-tracking remote name if any is found.
582	pub fn find_non_tracking_remote(list_output: &str, bookmark: &str) -> Option<String> {
583	    let prefix = format!("{bookmark}@");
584	    for line in list_output.lines() {
585	        if line.starts_with(&prefix)
586	            && let Some(rest) = line.strip_prefix(&prefix)
587	            && let Some((remote, _)) = rest.split_once(':')
588	        {
589	            return Some(remote.to_string());
590	        }
591	    }
592	    None
593	}
594	
595	/// Verify all remote refs for `bookmark` in `repo` are tracked.
596	///
597	/// Returns `Err` with the exact `jj bookmark track …` remediation command if
598	/// any non-tracking remote ref is found. Used as a preflight by repo-modifying
599	/// commands (sync, push, finalize) and as a post-condition assertion by setup
600	/// commands (init, clone, test-fixture).
601	pub fn verify_tracking(repo: &Path, bookmark: &str) -> Result<(), Box<dyn std::error::Error>> {
602	    let repo_str = repo.to_string_lossy();
603	    let cwd = Path::new(".");
604	    let all = run(
605	        "jj",
606	        &["bookmark", "list", "-a", bookmark, "-R", &repo_str],
607	        cwd,
608	    )?;
609	    if let Some(remote) = find_non_tracking_remote(&all, bookmark) {
610	        return Err(format!(
611	            "bookmark '{bookmark}' has non-tracking remote '{bookmark}@{remote}' — \
612	             run `jj bookmark track {bookmark} --remote={remote} -R {repo_str}` to fix"
613	        )
614	        .into());
615	    }
616	    Ok(())
617	}
618	
619	/// Walk up from `start` to find the workspace root.
620	///
621	/// The workspace root is the directory whose `.vc-config.toml` has
622	/// `path = "/"`. Returns `None` if no such config is found up to the
623	/// filesystem root — the caller is in a "plain old repo" (POR) with
624	/// no vc-x1 workspace metadata.
625	pub fn find_workspace_root_from(start: &Path) -> Option<PathBuf> {
626	    let mut cur = start.to_path_buf();
627	    loop {
628	        let cfg = cur.join(VC_CONFIG_FILE);
629	        if let Ok(map) = toml_simple::toml_load(&cfg)
630	            && toml_simple::toml_get(&map, "workspace.path").map(String::as_str) == Some("/")
631	        {
632	            return Some(cur);
633	        }
634	        cur = cur.parent()?.to_path_buf();
635	    }
636	}
637	
638	/// Cwd-anchored wrapper over [`find_workspace_root_from`].
639	pub fn find_workspace_root() -> Option<PathBuf> {
640	    let cur = std::env::current_dir().ok()?;
641	    find_workspace_root_from(&cur)
642	}
643	
644	/// Resolve the workspace's default `--scope`.
645	///
646	/// Reads `<workspace_root>/.vc-config.toml > [workspace] other-repo`:
647	///
648	/// - dual workspace (non-empty `other-repo`) → `Roles([Code, Bot])`
649	/// - single-repo workspace (missing / empty `other-repo`) → `Roles([Code])`
650	/// - POR (no workspace_root) → `Single(cwd)` — operate on cwd as a
651	///   one-off jj repo, ignoring any workspace context.
652	pub fn default_scope(workspace_root: Option<&Path>, cwd: &Path) -> Scope {
653	    let Some(root) = workspace_root else {
654	        return Scope::Single(cwd.to_path_buf());
655	    };
656	    let cfg = match toml_simple::toml_load(&root.join(VC_CONFIG_FILE)) {
657	        Ok(c) => c,
658	        Err(_) => return Scope::Roles(vec![Side::Code]),
659	    };
660	    match toml_simple::toml_get(&cfg, "workspace.other-repo") {
661	        Some(v) if !v.is_empty() => Scope::Roles(vec![Side::Code, Side::Bot]),
662	        _ => Scope::Roles(vec![Side::Code]),
663	    }
664	}
665	
666	/// Resolve a `Scope` to concrete repo paths.
667	///
668	/// `Roles(...)` arm:
669	///
670	/// - `Side::Code` → `workspace_root` (or cwd's `.` when `workspace_root` is None).
671	/// - `Side::Bot` → `workspace_root.join(other-repo)`.
672	///
673	/// Errors when `Side::Bot` is requested but the workspace doesn't define
674	/// one (POR or single-repo workspace).
675	///
676	/// `Single(p)` arm: returns `vec![p]` directly — no workspace lookup,
677	/// no `other-repo` resolution. The path is whatever the caller stored
678	/// (typically the value the user passed to `--scope=<path>`, or cwd
679	/// from `default_scope`'s POR branch); shell-style expansion (tilde,
680	/// `$VAR`) happens at the parser/consumer boundary, not here.
681	pub fn scope_to_repos(
682	    scope: &Scope,
683	    workspace_root: Option<&Path>,
684	) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
685	    let sides = match scope {
686	        Scope::Roles(v) => v,
687	        Scope::Single(p) => return Ok(vec![p.clone()]),
688	    };
689	    let mut repos = Vec::new();
690	    for side in sides {
691	        match side {
692	            Side::Code => repos.push(
693	                workspace_root
694	                    .map(Path::to_path_buf)
695	                    .unwrap_or_else(|| PathBuf::from(".")),
696	            ),
697	            Side::Bot => {
698	                let root = workspace_root.ok_or(
699	                    "--scope=bot: not in a vc-x1 workspace (no .vc-config.toml with path = \"/\") — drop --scope or use --scope=code",
700	                )?;
701	                let cfg = toml_simple::toml_load(&root.join(VC_CONFIG_FILE))?;
702	                let other = toml_simple::toml_get(&cfg, "workspace.other-repo")
703	                    .filter(|v| !v.is_empty())
704	                    .ok_or(
705	                        "--scope=bot: no other-repo configured. Add `other-repo = \"…\"` to .vc-config.toml to enable dual-repo operations",
706	                    )?;
707	                repos.push(root.join(other));
708	            }
709	        }
710	    }
711	    Ok(repos)
712	}
