1	use std::sync::Arc;
2	
3	use chrono::Offset;
4	use clap::Args;
5	use jj_lib::backend::TreeValue;
6	use jj_lib::commit::Commit;
7	use jj_lib::matchers::EverythingMatcher;
8	use jj_lib::merged_tree::TreeDiffIterator;
9	use jj_lib::object_id::ObjectId;
10	use jj_lib::repo::{ReadonlyRepo, Repo};
11	use jj_lib::workspace::Workspace;
12	use pollster::FutureExt;
13	
14	use log::{debug, info};
15	
16	use crate::common;
17	
18	/// Parsed file limit: None (suppress), Some(n) (cap at n), or all.
19	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
20	pub enum FileLimit {
21	    /// Don't show changed files section at all.
22	    None,
23	    /// Show up to N files (with first/last split if truncated).
24	    Cap(usize),
25	    /// Show all files.
26	    All,
27	}
28	
29	impl FileLimit {
30	    fn parse(s: &str) -> Result<Self, String> {
31	        match s {
32	            "0" => Ok(FileLimit::None),
33	            "all" => Ok(FileLimit::All),
34	            _ => s
35	                .parse::<usize>()
36	                .map(FileLimit::Cap)
37	                .map_err(|_| format!("invalid file limit '{s}': expected number, 0, or 'all'")),
38	        }
39	    }
40	}
41	
42	#[derive(Args, Debug)]
43	pub struct ShowArgs {
44	    #[command(flatten)]
45	    pub common: common::CommonArgs,
46	
47	    /// Max changed files: number, 0 (none), or 'all'
48	    #[arg(short = 'f', long = "files", default_value = "50")]
49	    pub files: String,
50	}
51	
52	pub fn show(args: &ShowArgs) -> Result<(), Box<dyn std::error::Error>> {
53	    debug!("show: enter");
54	    let file_limit = FileLimit::parse(&args.files)?;
55	    let c = &args.common;
56	
57	    let spec = common::resolve_spec(c.pos_rev.as_deref(), c.pos_count, &c.revision, c.limit, "@");
58	    let hdr = common::resolve_header(&c.label, c.no_label);
59	
60	    common::for_each_repo(&c.repos, &hdr, |workspace, repo| {
61	        let (ids, anchor_index) =
62	            common::collect_ids(workspace, repo, &spec.rev, spec.desc_count, spec.anc_count)?;
63	
64	        let mut first = true;
65	        for (i, commit_id) in ids.iter().enumerate() {
66	            if !first {
67	                info!("────────────────────────────────────────");
68	            }
69	            first = false;
70	
71	            let commit = repo.store().get_commit(commit_id)?;
72	            show_one_commit(&commit, workspace, repo, file_limit, i == anchor_index)?;
73	        }
74	        Ok(())
75	    })?;
76	    debug!("show: exit");
77	    Ok(())
78	}
79	
80	fn show_one_commit(
81	    commit: &Commit,
82	    workspace: &Workspace,
83	    repo: &Arc<ReadonlyRepo>,
84	    file_limit: FileLimit,
85	    is_primary: bool,
86	) -> Result<(), Box<dyn std::error::Error>> {
87	    // Author
88	    let author = commit.author();
89	    info!(
90	        "Author:    {} <{}> ({})",
91	        author.name,
92	        author.email,
93	        format_timestamp(&author.timestamp)
94	    );
95	
96	    // Committer
97	    let committer = commit.committer();
98	    info!(
99	        "Committer: {} <{}> ({})",
100	        committer.name,
101	        committer.email,
102	        format_timestamp(&committer.timestamp)
103	    );
104	
105	    // Ids
106	    let bookmarks = common::format_bookmarks_at(repo, commit.id());
107	    let ids_line = common::format_commit_short(commit, &bookmarks);
108	    if is_primary {
109	        info!("Ids:       {}", common::bold(&ids_line));
110	    } else {
111	        info!("Ids:       {ids_line}");
112	    }
113	
114	    // Parents
115	    let root_commit_id = repo.store().root_commit_id().clone();
116	    for parent_id in commit.parent_ids() {
117	        if *parent_id == root_commit_id {
118	            continue;
119	        }
120	        let parent = repo.store().get_commit(parent_id)?;
121	        let bm = common::format_bookmarks_at(repo, parent.id());
122	        info!("Parent:    {}", common::format_commit_short(&parent, &bm));
123	    }
124	
125	    // Children
126	    let children_ids =
127	        common::resolve_revset(workspace, repo, &format!("children({})", commit.id().hex()))?;
128	    for child_id in &children_ids {
129	        if *child_id == root_commit_id {
130	            continue;
131	        }
132	        let child = repo.store().get_commit(child_id)?;
133	        let bm = common::format_bookmarks_at(repo, child.id());
134	        info!("Child:     {}", common::format_commit_short(&child, &bm));
135	    }
136	
137	    // Branches
138	    let branches_str = format_branches(commit, workspace, repo)?;
139	    info!("Branches:  {branches_str}");
140	
141	    // Follows
142	    let follows = find_nearest_tag(commit, workspace, repo, true)?;
143	    info!("Follows:   {}", follows.as_deref().unwrap_or("")); // OK: obvious
144	
145	    // Precedes
146	    let precedes = find_nearest_tag(commit, workspace, repo, false)?;
147	    info!("Precedes:  {}", precedes.as_deref().unwrap_or("")); // OK: obvious
148	
149	    // Description (body only — title is on the Ids line)
150	    print_description(commit);
151	
152	    // Changed files
153	    if file_limit != FileLimit::None {
154	        print_diff(commit, repo, file_limit)?;
155	    }
156	
157	    Ok(())
158	}
159	
160	fn find_nearest_tag(
161	    commit: &Commit,
162	    workspace: &Workspace,
163	    repo: &Arc<ReadonlyRepo>,
164	    ancestor: bool,
165	) -> Result<Option<String>, Box<dyn std::error::Error>> {
166	    let commit_hex = commit.id().hex();
167	
168	    let revset_str = if ancestor {
169	        format!("heads(tags() & ::{})", commit_hex)
170	    } else {
171	        format!("roots(tags() & {}::)", commit_hex)
172	    };
173	
174	    let tag_ids = common::resolve_revset(workspace, repo, &revset_str)?;
175	    if tag_ids.is_empty() {
176	        return Ok(None);
177	    }
178	
179	    let tag_id = &tag_ids[0];
180	    let view = repo.view();
181	    for (name, local_remote) in view.tags() {
182	        if local_remote.local_target.added_ids().any(|id| id == tag_id) {
183	            return Ok(Some(name.as_str().to_string()));
184	        }
185	    }
186	
187	    Ok(None)
188	}
189	
190	fn format_branches(
191	    commit: &Commit,
192	    workspace: &Workspace,
193	    repo: &Arc<ReadonlyRepo>,
194	) -> Result<String, Box<dyn std::error::Error>> {
195	    let commit_hex = commit.id().hex();
196	    let view = repo.view();
197	    let mut names: Vec<String> = Vec::new();
198	
199	    for (name, local_remote) in view.bookmarks() {
200	        for bookmark_id in local_remote.local_target.added_ids() {
201	            let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
202	            let results = common::resolve_revset(workspace, repo, &revset_str)?;
203	            if !results.is_empty() {
204	                names.push(name.as_str().to_string());
205	                break;
206	            }
207	        }
208	
209	        for (remote_name, remote_ref) in &local_remote.remote_refs {
210	            if remote_name.as_str() == "git" {
211	                continue;
212	            }
213	            for bookmark_id in remote_ref.target.added_ids() {
214	                let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
215	                let results = common::resolve_revset(workspace, repo, &revset_str)?;
216	                if !results.is_empty() {
217	                    names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
218	                    break;
219	                }
220	            }
221	        }
222	    }
223	
224	    Ok(names.join(", "))
225	}
226	
227	fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
228	    let millis = ts.timestamp.0;
229	    let secs = millis / 1000;
230	    let tz_minutes = ts.tz_offset;
231	
232	    let dt = chrono::DateTime::from_timestamp(secs, 0)
233	        .unwrap_or_default() // OK: invalid timestamp → epoch for display
234	        .with_timezone(
235	            &chrono::FixedOffset::east_opt(tz_minutes * 60).unwrap_or(chrono::Utc.fix()), // OK: invalid tz → UTC for display
236	        );
237	
238	    dt.format("%Y-%m-%d %H:%M:%S").to_string()
239	}
240	
241	fn print_description(commit: &Commit) {
242	    let desc = commit.description();
243	    let body: String = desc
244	        .lines()
245	        .skip(1)
246	        .skip_while(|l| l.is_empty())
247	        .collect::<Vec<_>>()
248	        .join("\n");
249	
250	    info!("Description:");
251	    for line in body.lines() {
252	        info!("    {line}");
253	    }
254	}
255	
256	fn print_diff(
257	    commit: &Commit,
258	    repo: &Arc<ReadonlyRepo>,
259	    file_limit: FileLimit,
260	) -> Result<(), Box<dyn std::error::Error>> {
261	    let parent_tree = commit.parent_tree(repo.as_ref()).block_on()?;
262	    let commit_tree = commit.tree();
263	
264	    let diff_iter = TreeDiffIterator::new(&parent_tree, &commit_tree, &EverythingMatcher);
265	
266	    let mut lines: Vec<String> = Vec::new();
267	    for entry in diff_iter {
268	        let diff = entry.values?;
269	        let before = diff.before.as_resolved().cloned().flatten();
270	        let after = diff.after.as_resolved().cloned().flatten();
271	
272	        if matches!(&before, Some(TreeValue::Tree(_))) || matches!(&after, Some(TreeValue::Tree(_)))
273	        {
274	            continue;
275	        }
276	
277	        let path_str = entry.path.as_internal_file_string().to_string();
278	
279	        let line = match (before, after) {
280	            (None, Some(value)) => {
281	                format!("    Added {} {path_str}", file_type_str(&value))
282	            }
283	            (Some(_), None) => {
284	                format!(
285	                    "    Removed {} {path_str}",
286	                    file_type_str_from_merged(&diff.before),
287	                )
288	            }
289	            (Some(_), Some(value)) => {
290	                format!("    Modified {} {path_str}", file_type_str(&value))
291	            }
292	            (None, None) => continue,
293	        };
294	        lines.push(line);
295	    }
296	
297	    let total = lines.len();
298	    let cap = match file_limit {
299	        FileLimit::All | FileLimit::None => 0,
300	        FileLimit::Cap(n) => n,
301	    };
302	    let show_all = cap == 0 || total <= cap;
303	
304	    if show_all {
305	        info!("Changed files: {total}");
306	        for line in &lines {
307	            info!("{line}");
308	        }
309	    } else {
310	        info!("Changed files: {total}, showing first {cap}");
311	        for line in &lines[..cap] {
312	            info!("{line}");
313	        }
314	    }
315	
316	    Ok(())
317	}
318	
319	fn file_type_str(value: &TreeValue) -> &'static str {
320	    match value {
321	        TreeValue::File {
322	            executable: false, ..
323	        } => "regular file",
324	        TreeValue::File {
325	            executable: true, ..
326	        } => "executable file",
327	        TreeValue::Symlink(_) => "symlink",
328	        TreeValue::Tree(_) => "tree",
329	        TreeValue::GitSubmodule(_) => "git submodule",
330	    }
331	}
