/// Clap-free counterpart of [`CommonArgs`], built at the binary edge.
///
/// The read-only subcommands (chid, desc, list, show) all resolve
/// their flattened `CommonArgs` into a [`DotSpec`] + [`Header`] before
/// iterating repos; `CommonParams` carries that resolved shape so the
/// op bodies never touch the clap struct.
///
/// - `spec`: bare revision plus per-side (descendant / ancestor)
///   counts, from [`resolve_spec`] over the positional / `-r` / `-n`
///   args (default rev `@`).
/// - `header`: how to decorate output between repos in multi-repo runs
///   (`-l` / `-L`), from [`resolve_header`].
/// - `repos`: the raw `-R` / `--repo` paths; comma-expansion and the
///   `.` default happen in [`for_each_repo`].
#[derive(Debug, Clone)]
pub struct CommonParams {
    pub spec: DotSpec,
    pub header: Header,
    pub repos: Vec<PathBuf>,
}

