//! `chid` subcommand — print the short change ID of each commit in a
//! revision range, one per line (script-friendly output).
//!
//! - `ChidArgs`: clap surface; flattens [`common::CommonArgs`].
//! - `ChidParams`: clap-free inputs (wraps [`common::CommonParams`]),
//!   built `From<&ChidArgs>` at the binary edge.
//! - `chid(&Context, &ChidParams)`: the op; `ctx` is the
//!   uniform-signature placeholder, unused today.

use clap::Args;
use jj_lib::repo::Repo;
use log::{debug, info};

use crate::common::{self, CommonParams};
use crate::context::Context;

/// CLI args for `chid` — just the shared read-only arg set.
#[derive(Args, Debug)]
pub struct ChidArgs {
    #[command(flatten)]
    pub common: common::CommonArgs,
}

/// Clap-free inputs to the `chid` op.
///
/// - `common`: the resolved shared args ([`DotSpec`](common::DotSpec)
///   + [`Header`](common::Header) + repo paths).
#[derive(Debug, Clone)]
pub struct ChidParams {
    pub common: CommonParams,
}

impl From<&ChidArgs> for ChidParams {
    /// Convert clap-derived `ChidArgs` into the flat `ChidParams`.
    fn from(a: &ChidArgs) -> Self {
        Self {
            common: CommonParams::from(&a.common),
        }
    }
}

/// Print the short change ID of each commit in the resolved range.
///
/// `ctx` is unused today (chid reads neither user config nor `--log`);
/// it's the uniform-signature placeholder shared by all subcommands.
pub fn chid(_ctx: &Context, params: &ChidParams) -> Result<(), Box<dyn std::error::Error>> {
    debug!("chid: enter");
    let c = &params.common;

    common::for_each_repo(&c.repos, &c.header, |workspace, repo| {
        let (ids, _) =
            common::collect_ids(workspace, repo, &c.spec.rev, c.spec.desc_count, c.spec.anc_count)?;

        for commit_id in &ids {
            let commit = repo.store().get_commit(commit_id)?;
            info!("{}", common::format_chid(&commit));
        }
        Ok(())
    })?;
    debug!("chid: exit");
    Ok(())
}

#[cfg(test)]
mod tests {
    use std::path::PathBuf;

    use clap::Parser;

    use crate::{Cli, Commands};

    fn parse(args: &[&str]) -> crate::common::CommonArgs {
        let cli = Cli::try_parse_from(args).unwrap();
        match cli.command {
            Commands::Chid(a) => a.common,
            _ => panic!("expected Chid"),
        }
    }

    #[test]
    fn defaults() {
        let c = parse(&["vc-x1", "chid"]);
        assert_eq!(c.revision, "@");
        assert!(c.repos.is_empty());
        assert_eq!(c.limit, None);
    }

    #[test]
    fn with_revision() {
        let c = parse(&["vc-x1", "chid", "-r", "@-"]);
        assert_eq!(c.revision, "@-");
    }

    #[test]
    fn with_repo() {
        let c = parse(&["vc-x1", "chid", "-R", ".claude"]);
        assert_eq!(c.repos, vec![PathBuf::from(".claude")]);
    }

    #[test]
    fn with_limit() {
        let c = parse(&["vc-x1", "chid", "-n", "5"]);
        assert_eq!(c.limit, Some(5));
    }

    #[test]
    fn all_opts() {
        let c = parse(&["vc-x1", "chid", "-r", "@--", "-R", ".claude", "-n", "3"]);
        assert_eq!(c.revision, "@--");
        assert_eq!(c.repos, vec![PathBuf::from(".claude")]);
        assert_eq!(c.limit, Some(3));
    }

    #[test]
    fn multi_repo() {
        let c = parse(&["vc-x1", "chid", "-R", ".", "-R", ".claude"]);
        assert_eq!(c.repos, vec![PathBuf::from("."), PathBuf::from(".claude")]);
    }

    #[test]
    fn comma_repo() {
        let c = parse(&["vc-x1", "chid", "-R", ".,.claude"]);
        assert_eq!(c.repos, vec![PathBuf::from(".,.claude")]);
    }

    #[test]
    fn label_default() {
        let c = parse(&["vc-x1", "chid"]);
        assert_eq!(c.label, "===");
        assert!(!c.no_label);
    }

    #[test]
    fn label_custom() {
        let c = parse(&["vc-x1", "chid", "-l", "---"]);
        assert_eq!(c.label, "---");
    }

    #[test]
    fn no_label() {
        let c = parse(&["vc-x1", "chid", "-L"]);
        assert!(c.no_label);
    }

    #[test]
    fn positional_rev() {
        let c = parse(&["vc-x1", "chid", "@-"]);
        assert_eq!(c.pos_rev, Some("@-".to_string()));
        assert_eq!(c.pos_count, None);
    }

    #[test]
    fn positional_rev_and_count() {
        let c = parse(&["vc-x1", "chid", "@..", "5"]);
        assert_eq!(c.pos_rev, Some("@..".to_string()));
        assert_eq!(c.pos_count, Some(5));
    }

    #[test]
    fn positional_both_dots() {
        let c = parse(&["vc-x1", "chid", "..abcd..", "3"]);
        assert_eq!(c.pos_rev, Some("..abcd..".to_string()));
        assert_eq!(c.pos_count, Some(3));
    }

    /// `ChidParams::from(&ChidArgs)` resolves the shared args at the
    /// binary edge — `@.. 5` → 4 ancestors, no descendants; `-L` →
    /// `Header::None`.
    #[test]
    fn params_from_args() {
        let cli = Cli::try_parse_from(["vc-x1", "chid", "@..", "5", "-L"]).unwrap();
        let args = match cli.command {
            Commands::Chid(a) => a,
            _ => panic!("expected Chid"),
        };
        let p = super::ChidParams::from(&args);
        assert_eq!(p.common.spec.rev, "@");
        assert_eq!(p.common.spec.desc_count, Some(0));
        assert_eq!(p.common.spec.anc_count, Some(4));
        assert!(matches!(p.common.header, crate::common::Header::None));
        assert!(p.common.repos.is_empty());
    }
}

