    #[test]
    fn params_from_args() {
        let cli = Cli::try_parse_from(["vc-x1", "chid", "@..", "5", "-L"]).unwrap();
        let args = match cli.command {
            Commands::Chid(a) => a,
            _ => panic!("expected Chid"),
        };
        let p = super::ChidParams::from(&args);
        assert_eq!(p.common.spec.rev, "@");
        assert_eq!(p.common.spec.desc_count, Some(0));
