1	//! Which side(s) of a workspace a command should operate on.
2	//!
3	//! - `Side` is the clap `ValueEnum` — one of `code`, `bot`.
4	//! - `Scope` is an enum:
5	//!   - `Roles(Vec<Side>)` — dual-repo workspace; the parsed
6	//!     keyword form (`code`, `bot`, `code,bot`, `bot,code`).
7	//!   - `Single(PathBuf)` — explicit single-repo mode; ignores
8	//!     `.vc-config.toml` and operates on the one repo at the
9	//!     given path. Wired up incrementally (parser lands in
10	//!     0.42.0-2, consumers in later steps).
11	//! - Helpers (`has_code`, `is_both`, etc.) reflect the `Roles`
12	//!   arm only; on `Single(_)` they all return `false`. Callers
13	//!   that must distinguish modes match on the enum directly.
14	//! - See `notes/chores-07.md > --scope enum refactor (0.42.0)`
15	//!   for the migration plan, and `notes/chores-06.md > 0.41.0-4`
16	//!   for the vocabulary capture.
17	
18	use clap::ValueEnum;
19	use std::fmt;
20	use std::path::PathBuf;
21	
22	/// One side of a dual-repo workspace.
23	///
24	/// - `Code` — the primary (app) repo.
25	/// - `Bot` — the Claude Code session repo (typically at `.claude/`).
26	#[derive(Copy, Clone, Debug, PartialEq, Eq, ValueEnum)]
27	pub enum Side {
28	    Code,
29	    Bot,
30	}
31	
32	/// Parsed `--scope` value.
33	///
34	/// - `Roles(_)` — dual-repo workspace; the requested side set.
35	/// - `Single(_)` — explicit single-repo mode at the given path.
36	#[derive(Clone, Debug, PartialEq, Eq)]
37	pub enum Scope {
38	    Roles(Vec<Side>),
39	    #[allow(dead_code)]
40	    Single(PathBuf),
41	}
42	
43	/// Parse a `--scope` value string.
44	///
45	/// Accepted forms:
46	///
47	/// - Keyword: exactly one of `code`, `bot`, `code,bot`, `bot,code`
48	///   → `Scope::Roles(...)`. Order is preserved.
49	/// - Path: starts with `./`, `../`, `/`, `~/`, or is the bare `~`
50	///   → `Scope::Single(PathBuf)`. The raw string is stored; tilde
51	///   and `$VAR` expansion happens at the consumer (see
52	///   `init::expand_vars`).
53	///
54	/// Anything else — including a bare unprefixed name like `foo`, an
55	/// empty string, or an unrecognized keyword combination — is an
56	/// error. The error message hints at the path-prefix requirement
57	/// so users see the disambiguation rule when they mistype.
58	#[allow(dead_code)]
59	pub fn parse_scope(s: &str) -> Result<Scope, String> {
60	    if s == "~"
61	        || s.starts_with("./")
62	        || s.starts_with("../")
63	        || s.starts_with('/')
64	        || s.starts_with("~/")
65	    {
66	        return Ok(Scope::Single(PathBuf::from(s)));
67	    }
68	    match s {
69	        "code" => Ok(Scope::Roles(vec![Side::Code])),
70	        "bot" => Ok(Scope::Roles(vec![Side::Bot])),
71	        "code,bot" => Ok(Scope::Roles(vec![Side::Code, Side::Bot])),
72	        "bot,code" => Ok(Scope::Roles(vec![Side::Bot, Side::Code])),
73	        "" => Err("--scope: value is empty".into()),
74	        other => Err(format!(
75	            "--scope: '{other}' is not a recognized form. \
76	             Expected one of `code`, `bot`, `code,bot`, `bot,code`, \
77	             or a path (`./X`, `../X`, `/X`, `~/X`). \
78	             Bare names without `./` are reserved for keywords; \
79	             prefix paths with `./` to disambiguate."
80	        )),
81	    }
82	}
83	
84	impl Scope {
85	    /// True when the `Roles` arm includes the code side.
86	    pub fn has_code(&self) -> bool {
87	        matches!(self, Scope::Roles(v) if v.contains(&Side::Code))
88	    }
89	
90	    /// True when the `Roles` arm includes the bot side.
91	    pub fn has_bot(&self) -> bool {
92	        matches!(self, Scope::Roles(v) if v.contains(&Side::Bot))
93	    }
94	
95	    /// Roles-only with exactly the code side — single-side dual-repo op.
96	    pub fn is_code_only(&self) -> bool {
97	        self.has_code() && !self.has_bot()
98	    }
99	
100	    /// Roles-only with exactly the bot side — single-side dual-repo op.
101	    #[allow(dead_code)]
102	    pub fn is_bot_only(&self) -> bool {
103	        !self.has_code() && self.has_bot()
104	    }
105	
106	    /// Roles arm including both sides — full dual-repo op.
107	    pub fn is_both(&self) -> bool {
108	        self.has_code() && self.has_bot()
109	    }
110	}
111	
112	/// Render a `Scope` as the canonical string form `parse_scope` accepts.
113	///
114	/// - `Roles(_)` → `code` / `bot` / `code,bot` / `bot,code` (preserves
115	///   original side ordering).
116	/// - `Single(p)` → the path's lossy display form. The stored path
117	///   already carries a parser-recognized prefix (the parser is the
118	///   only constructor of `Single`), so the round-trip through
119	///   `parse_scope` is well-defined.
120	impl fmt::Display for Scope {
121	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
122	        match self {
123	            Scope::Roles(sides) => {
124	                let parts: Vec<&'static str> = sides
125	                    .iter()
126	                    .map(|s| match s {
127	                        Side::Code => "code",
128	                        Side::Bot => "bot",
129	                    })
130	                    .collect();
131	                f.write_str(&parts.join(","))
132	            }
133	            Scope::Single(p) => write!(f, "{}", p.display()),
134	        }
135	    }
136	}
137	
138	#[cfg(test)]
139	mod tests {
140	    use super::*;
141	
142	    #[test]
143	    fn code_only() {
144	        let s = Scope::Roles(vec![Side::Code]);
145	        assert!(s.is_code_only());
146	        assert!(!s.is_bot_only());
147	        assert!(!s.is_both());
148	    }
149	
150	    #[test]
151	    fn bot_only() {
152	        let s = Scope::Roles(vec![Side::Bot]);
153	        assert!(!s.is_code_only());
154	        assert!(s.is_bot_only());
155	        assert!(!s.is_both());
156	    }
157	
158	    #[test]
159	    fn both_code_then_bot() {
160	        let s = Scope::Roles(vec![Side::Code, Side::Bot]);
161	        assert!(!s.is_code_only());
162	        assert!(!s.is_bot_only());
163	        assert!(s.is_both());
164	    }
165	
166	    #[test]
167	    fn both_bot_then_code() {
168	        // Order doesn't matter — contains-based checks.
169	        let s = Scope::Roles(vec![Side::Bot, Side::Code]);
170	        assert!(s.is_both());
171	    }
172	
173	    #[test]
174	    fn empty_roles() {
175	        // Empty side list isn't a state anything constructs (the
176	        // parser rejects empty input), but the helpers still need
177	        // to be well-defined on it.
178	        let s = Scope::Roles(vec![]);
179	        assert!(!s.is_code_only());
180	        assert!(!s.is_bot_only());
181	        assert!(!s.is_both());
182	    }
183	
184	    #[test]
185	    fn single_helpers_all_false() {
186	        // `Single(_)` is a distinct mode; the Roles-shaped helpers
187	        // all report false so callers that match on helpers
188	        // naturally fall through to mode-aware logic.
189	        let s = Scope::Single(PathBuf::from("/some/repo"));
190	        assert!(!s.has_code());
191	        assert!(!s.has_bot());
192	        assert!(!s.is_code_only());
193	        assert!(!s.is_bot_only());
194	        assert!(!s.is_both());
195	    }
196	
197	    // ---------- parse_scope ----------
198	
199	    #[test]
