//! [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--commits` leaf (Option — non-boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
///
/// - The single field is named `value`; the flag name comes from
///   `#[arg(short = 'n', long = "commits")]`, so the consumer reads
///   `args.<leaf>.value`.
/// - `Some(n)` caps the output at `n` commits; `None` (the default)
///   means "use the positional / dot spec, unbounded otherwise".
///   `common::resolve_spec` reconciles this with the `COMMITS`
///   positional.
#[derive(Args, Debug, Clone, Default)]
pub struct CommitLimitOption {
    /// Number of commits to show
    #[arg(short = 'n', long = "commits", value_name = "COMMITS")]
    pub value: Option<usize>,
}

