//! `-l` / `--label` + `-L` / `--no-label` — the decoration printed
//! between repos in multi-repo output, and whether it's shown at all.
//! See [options_flags](README.md) for shared architecture.

use clap::Args;

/// Inter-repo label leaf — a coupled Option + Flag pair modeled as
/// one leaf because the decoration string and its suppress switch
/// are one conceptual knob (cf. `push_retry`'s count + delay pair).
/// See [Bundle vs leaf](README.md#architecture).
///
/// - `label` — the decoration wrapping each repo's path header in
///   multi-repo output (`-l` / `--label`, default `===`; hyphen
///   values allowed so `-l ---` works).
/// - `no_label` — suppress the header entirely (`-L` / `--no-label`);
///   takes precedence over `label`.
/// - `common::resolve_header` combines the pair into a `Header`.
#[derive(Args, Debug, Clone)]
pub struct RepoLabelOptions {
    /// Custom label decoration between repos
    #[arg(
        short = 'l',
        long = "label",
        value_name = "TEXT",
        allow_hyphen_values = true,
        default_value = "==="
    )]
    pub label: String,

    /// Suppress label between repos
    #[arg(short = 'L', long = "no-label")]
    pub no_label: bool,
}

impl Default for RepoLabelOptions {
    /// Mirrors the clap defaults: `label = "==="`, `no_label = false`.
    fn default() -> Self {
        Self {
            label: "===".to_string(),
            no_label: false,
        }
    }
}

