//! `CommonOptionFlagBundle` — the OFs shared by the read-only
//! commit-query subcommands (`chid`, `desc`, `list`, `show`).
//!
//! Composes `RevisionOption`, `CommitLimitOption` (Option leaves)
//! and `RepoLabelOptions` (a coupled Option + Flag pair), plus the
//! two positionals (`REVISION` / `COMMITS`) and the `-R` / `--repo`
//! repo list inline. Mixed-domain → implements `OptionFlagBundle`.
//!
//! - The `-R` / `--repo` field is slated for replacement by a
//!   `--scope` leaf in 0.49.0-6 (`notes/chores-09.md`).
//! - The positionals stay inline — no second consumer would compose
//!   them independently.
//!
//! See [options_flags](README.md) for shared architecture.

use std::path::PathBuf;

use clap::Args;

use super::commit_limit::CommitLimitOption;
use super::repo_label::RepoLabelOptions;
use super::revision::RevisionOption;

/// Read-only commit-query bundle — see [Bundle](README.md#architecture).
///
/// - `pos_rev` / `pos_count` — the `REVISION` / `COMMITS` positionals
///   (inline; `common::resolve_spec` reconciles them with the
///   `-r` / `-n` flags).
/// - `revision` — `-r` / `--revision` (Option leaf).
/// - `repos` — `-R` / `--repo`, repeatable / comma-separated repo
///   paths (inline; the `.` default is applied in
///   `common::for_each_repo`).
/// - `limit` — `-n` / `--commits` (Option leaf).
/// - `repo_label` — `-l` / `--label` + `-L` / `--no-label` (leaf).
#[derive(Args, Debug, Clone, Default)]
pub struct CommonOptionFlagBundle {
    /// Revision (with optional .. notation)
    #[arg(value_name = "REVISION")]
    pub pos_rev: Option<String>,

    /// Number of commits to show (per dotted side)
    #[arg(value_name = "COMMITS")]
    pub pos_count: Option<usize>,

    #[command(flatten)]
    pub revision: RevisionOption,

    /// Path to jj repo; repeatable or comma-separated [default: .]
    #[arg(short = 'R', long = "repo", value_name = "PATH")]
    pub repos: Vec<PathBuf>,

    #[command(flatten)]
    pub limit: CommitLimitOption,

    #[command(flatten)]
    pub repo_label: RepoLabelOptions,
}

impl super::OptionFlagBundle for CommonOptionFlagBundle {}

