//!
//! - `DescArgs`: clap surface; flattens
//!   `options_flags::common_bundle::CommonOptionFlagBundle`.
//! - `desc(&DescArgs)`: the op — `resolve_spec` / `resolve_header` /
//!   `for_each_repo` + `format_commit_full` + `indent_body`.

use clap::Args;
use jj_lib::repo::Repo;
use log::{debug, info};

use crate::common;
use crate::options_flags::common_bundle::CommonOptionFlagBundle;

/// CLI args for `desc` — just the shared read-only commit-query OFs.
#[derive(Args, Debug)]
pub struct DescArgs {
    #[command(flatten)]
    pub common: CommonOptionFlagBundle,
}

/// Print each commit in the resolved range with its full description.
pub fn desc(args: &DescArgs) -> Result<(), Box<dyn std::error::Error>> {
    debug!("desc: enter");
    let c = &args.common;
    let spec = common::resolve_spec(
        c.pos_rev.as_deref(),
        c.pos_count,
        &c.revision.value,
        c.limit.value,
        "@",
    );
    let hdr = common::resolve_header(&c.repo_label.label, c.repo_label.no_label);

    common::for_each_repo(&c.repos, &hdr, |workspace, repo| {
        let (ids, anchor_index) =
            common::collect_ids(workspace, repo, &spec.rev, spec.desc_count, spec.anc_count)?;

        for (i, commit_id) in ids.iter().enumerate() {
            let commit = repo.store().get_commit(commit_id)?;
            let bookmarks = common::format_bookmarks_at(repo, commit_id);
