99	fn show_one_commit(
100	    commit: &Commit,
101	    workspace: &Workspace,
102	    repo: &Arc<ReadonlyRepo>,
103	    file_limit: FileLimit,
104	    is_primary: bool,
105	) -> Result<(), Box<dyn std::error::Error>> {
106	    // Author
107	    let author = commit.author();
108	    info!(
109	        "Author:    {} <{}> ({})",
110	        author.name,
111	        author.email,
112	        format_timestamp(&author.timestamp)
113	    );
114	
115	    // Committer
116	    let committer = commit.committer();
117	    info!(
118	        "Committer: {} <{}> ({})",
119	        committer.name,
120	        committer.email,
121	        format_timestamp(&committer.timestamp)
122	    );
123	
124	    // Ids
125	    let bookmarks = common::format_bookmarks_at(repo, commit.id());
126	    let ids_line = common::format_commit_short(commit, &bookmarks);
127	    if is_primary {
