129	    } else {
130	        info!("Ids:       {ids_line}");
131	    }
132	
133	    // Parents
134	    let root_commit_id = repo.store().root_commit_id().clone();
135	    for parent_id in commit.parent_ids() {
136	        if *parent_id == root_commit_id {
137	            continue;
138	        }
139	        let parent = repo.store().get_commit(parent_id)?;
140	        let bm = common::format_bookmarks_at(repo, parent.id());
141	        info!("Parent:    {}", common::format_commit_short(&parent, &bm));
142	    }
143	
144	    // Children
145	    let children_ids =
146	        common::resolve_revset(workspace, repo, &format!("children({})", commit.id().hex()))?;
147	    for child_id in &children_ids {
148	        if *child_id == root_commit_id {
149	            continue;
150	        }
151	        let child = repo.store().get_commit(child_id)?;
152	        let bm = common::format_bookmarks_at(repo, child.id());
153	        info!("Child:     {}", common::format_commit_short(&child, &bm));
154	    }
155	
156	    // Branches
157	    let branches_str = format_branches(commit, workspace, repo)?;
158	    info!("Branches:  {branches_str}");
159	
160	    // Follows
161	    let follows = find_nearest_tag(commit, workspace, repo, true)?;
162	    info!("Follows:   {}", follows.as_deref().unwrap_or("")); // OK: obvious
163	
164	    // Precedes
