//! `-r` / `--revision` — the revision to query (with optional `..`
//! notation). See [options_flags](README.md) for shared architecture.

use clap::Args;

/// `--revision` leaf (Option — non-boolean domain) — see
/// [Consuming an OF](README.md#consuming-an-of).
///
/// - The single field is named `value` (the parsed value-side of the
///   option); the flag name comes from `#[arg(short = 'r', long =
///   "revision")]`, so the consumer reads `args.<leaf>.value`.
/// - Defaults to `@` (the working-copy commit).
/// - The `..` notation (`x..`, `..x`, `..x..`) is parsed downstream
///   by `common::parse_dot_rev`, not here — this leaf carries the raw
///   string.
#[derive(Args, Debug, Clone)]
pub struct RevisionOption {
    /// Revision to query (with optional .. notation)
    #[arg(
        short = 'r',
        long = "revision",
        value_name = "REVISION",
        default_value = "@"
    )]
    pub value: String,
}

impl Default for RevisionOption {
    /// Mirrors the clap `default_value = "@"`.
    fn default() -> Self {
        Self {
            value: "@".to_string(),
        }
    }
}

